<script setup>
import { onMounted, ref } from 'vue'
import { RouterLink, useRouter } from 'vue-router'
import { authState, clearSession } from '../services/authApi'
import { getAdminDashboard, getAdminUsers, updateAdminUserRole } from '../services/adminApi'
const router = useRouter(); const stats = ref(null); const users = ref([]); const error = ref(''); const notice = ref('')
const load = async () => { try { [stats.value, users.value] = await Promise.all([getAdminDashboard(), getAdminUsers()]) } catch (e) { error.value = e.message } }
const updateRole = async user => { try { await updateAdminUserRole(user.id, user.role); notice.value = `Đã đổi vai trò của ${user.displayName} thành ${user.role}.`; stats.value = await getAdminDashboard() } catch (e) { error.value = e.message } }
const logout = async () => { clearSession(); await router.replace('/') }
const labels = { users: 'Người dùng', staff: 'Nhân viên', admins: 'Quản trị viên', eventComments: 'Bình luận', forumTopics: 'Chủ đề', forumPosts: 'Phản hồi', pendingTopUps: 'Nạp chờ duyệt', characters: 'Nhân vật', events: 'Sự kiện', releaseEntries: 'Mốc ra mắt' }
onMounted(load)
</script>
<template><main class="min-h-screen px-4 py-16 sm:px-6 sm:py-24"><div class="mx-auto max-w-7xl"><header class="mb-8 flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between"><div><p class="text-xs font-black uppercase tracking-[0.24em] text-opm-gold">Trang quản trị viên</p><h1 class="mt-2 text-4xl font-black text-white">Dashboard</h1><p class="mt-2 text-gray-400">{{ authState.session?.displayName }} · toàn bộ dữ liệu hệ thống</p></div><button class="rounded-xl border border-white/10 px-4 py-2 text-sm font-bold text-gray-300" @click="logout">Đăng xuất</button></header><p v-if="notice" class="mb-4 rounded-xl bg-emerald-500/10 p-3 text-emerald-300">{{ notice }}</p><p v-if="error" class="mb-4 rounded-xl bg-red-500/10 p-3 text-red-300">{{ error }}</p><section v-if="stats" class="grid grid-cols-2 gap-4 md:grid-cols-3 xl:grid-cols-5"><article v-for="(value, key) in stats" :key="key" class="rounded-2xl border border-white/10 bg-[#0b0d13] p-5"><p class="text-xs font-bold uppercase tracking-wider text-gray-500">{{ labels[key] || key }}</p><strong class="mt-2 block text-3xl font-black text-white">{{ value }}</strong></article></section><nav class="my-8 grid gap-4 md:grid-cols-2 xl:grid-cols-4"><RouterLink to="/admin/characters" class="rounded-2xl border border-opm-gold/30 bg-opm-gold/5 p-5"><strong class="text-lg text-opm-gold">Nhân vật & Kỷ vật</strong><p class="mt-2 text-sm text-gray-400">Thêm, sửa, xóa dữ liệu nhân vật.</p></RouterLink><RouterLink to="/admin/releases" class="rounded-2xl border border-amber-500/30 bg-amber-500/5 p-5"><strong class="text-lg text-amber-300">Lịch ra mắt tướng</strong><p class="mt-2 text-sm text-gray-400">Điều khiển banner CN/SEA trên trang chủ.</p></RouterLink><RouterLink to="/admin/events" class="rounded-2xl border border-purple-500/30 bg-purple-500/5 p-5"><strong class="text-lg text-purple-300">Sự kiện</strong><p class="mt-2 text-sm text-gray-400">Quản lý lịch và nội dung sự kiện.</p></RouterLink><RouterLink to="/staff" class="rounded-2xl border border-cyan-500/30 bg-cyan-500/5 p-5"><strong class="text-lg text-cyan-300">Khu vực nhân viên</strong><p class="mt-2 text-sm text-gray-400">Duyệt nạp và kiểm duyệt cộng đồng.</p></RouterLink></nav><section class="rounded-2xl border border-white/10 bg-[#0b0d13] p-5"><h2 class="text-xl font-black text-white">Người dùng & phân quyền</h2><div class="mt-4 overflow-x-auto"><table class="w-full min-w-[720px] text-left text-sm"><thead class="text-xs uppercase text-gray-500"><tr><th class="p-3">Tài khoản</th><th class="p-3">Tên hiển thị</th><th class="p-3">Số dư</th><th class="p-3">Ngày tạo</th><th class="p-3">Vai trò</th></tr></thead><tbody class="divide-y divide-white/5"><tr v-for="user in users" :key="user.id"><td class="p-3 font-bold text-white">{{ user.username }}</td><td class="p-3 text-gray-300">{{ user.displayName }}</td><td class="p-3 text-opm-gold">{{ Number(user.balance).toLocaleString('vi-VN') }}đ</td><td class="p-3 text-gray-500">{{ new Date(user.createdAt).toLocaleDateString('vi-VN') }}</td><td class="p-3"><select v-model="user.role" class="rounded-lg border border-white/10 bg-black/30 px-3 py-2 text-white" @change="updateRole(user)"><option>User</option><option>Staff</option><option>Admin</option></select></td></tr></tbody></table><p v-if="users.length === 0" class="py-8 text-center text-gray-500">Chưa có tài khoản cộng đồng.</p></div></section></div></main></template>
